{
  "domain_analysis": {
    "business_context": "Evolution of shipment domain model from a 1:1 Shipment-Recipient relationship to a 1:N relationship, enabling multi-recipient shipments. This is a fundamental structural change to a core aggregate in the delivery platform, affecting ~2M existing shipments and external partner integrations.",
    "bounded_context": "Shipment Fulfillment / Delivery Management",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "A unit of goods being transported from origin to one or more delivery destinations. The root aggregate in this bounded context." },
      { "term": "Recipient", "definition": "A party designated to receive a delivery. Characterized by name, address, phone number, and delivery preferences. Formerly embedded in Shipment; now a first-class entity within the Shipment aggregate." },
      { "term": "Delivery Preferences", "definition": "Recipient-specific instructions governing how, when, and where delivery should occur (e.g., safe place, time window, signature required, authority to leave)." },
      { "term": "Primary Recipient", "definition": "The designated main recipient on a multi-recipient shipment, used as the default contact and for backward-compatible API responses. MUST be explicitly defined if multiple recipients exist." },
      { "term": "Recipient Order", "definition": "The sequenced delivery plan across recipients within a single shipment. Determines routing and delivery sequence." },
      { "term": "Split Delivery", "definition": "A shipment fulfillment pattern where goods within a single shipment are delivered to multiple recipients, potentially at different addresses and times." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A Shipment MUST have at least one Recipient at all times. A Shipment with zero Recipients is invalid.",
      "invariant": true,
      "invariant_justification": "A shipment without a recipient has no delivery destination and cannot exist in a logically consistent state. This is a structural integrity constraint — the system cannot route, price, or fulfill a shipment with no recipient.",
      "testable_assertion": "Given a Shipment, when all Recipients are removed, then the operation MUST be rejected and the Shipment retains its last Recipient."
    },
    {
      "id": "BR-2",
      "rule": "Each Recipient within a Shipment MUST have a valid name, address, and phone number.",
      "invariant": true,
      "invariant_justification": "These are the minimum data elements required to attempt delivery. Without them the courier cannot locate the destination, identify the recipient, or make contact. Data integrity constraint.",
      "testable_assertion": "Given a Recipient being added to a Shipment, when name, address, or phone number is missing or invalid, then the addition MUST be rejected."
    },
    {
      "id": "BR-3",
      "rule": "Each Recipient within a Shipment MUST have an independently defined set of delivery preferences. Preferences do not cascade from the Shipment or from other Recipients.",
      "invariant": false,
      "invariant_justification": "Delivery preferences are a business policy concern. A VP could decide to introduce default preferences or shipment-level preference inheritance. The requirement today is per-recipient independence, but this is policy, not structural integrity.",
      "testable_assertion": "Given a Shipment with Recipients A and B, when Recipient A's delivery preferences are updated, then Recipient B's preferences MUST remain unchanged."
    },
    {
      "id": "BR-4",
      "rule": "When a Shipment has multiple Recipients, exactly one Recipient MUST be designated as the Primary Recipient.",
      "invariant": true,
      "invariant_justification": "External partner APIs and downstream systems require a single point of contact and a canonical address for the shipment. Without a designated primary, backward compatibility breaks and routing decisions become ambiguous. This is a data consistency constraint.",
      "testable_assertion": "Given a Shipment with more than one Recipient, when no Primary Recipient is designated, then the Shipment MUST be invalid. When the Primary Recipient is removed, a new Primary MUST be designated before the operation completes."
    },
    {
      "id": "BR-5",
      "rule": "All existing single-recipient shipments MUST be automatically treated as having that recipient as the Primary Recipient with no data loss or behavioral change.",
      "invariant": true,
      "invariant_justification": "2 million production records must maintain semantic equivalence through the migration. Any change in behavior for existing shipments represents data corruption at scale.",
      "testable_assertion": "Given a pre-migration Shipment with one Recipient, when the system is migrated, then the Shipment MUST have exactly one Recipient marked as Primary, with identical name, address, phone, and all existing delivery behavior preserved."
    },
    {
      "id": "BR-6",
      "rule": "Each Recipient within a Shipment MUST have an independent delivery status. A Shipment is only fully delivered when ALL Recipients have been delivered to.",
      "invariant": true,
      "invariant_justification": "Delivery status is a physical-world constraint. If one recipient received their goods but another did not, the shipment is not complete. Misrepresenting this corrupts delivery state.",
      "testable_assertion": "Given a Shipment with Recipients A and B, when A is marked delivered but B is not, then the Shipment status MUST NOT be 'Delivered'. When both A and B are marked delivered, THEN the Shipment status becomes 'Delivered'."
    },
    {
      "id": "BR-7",
      "rule": "Recipient uniqueness within a Shipment is determined by address. The same address MUST NOT appear more than once within a single Shipment.",
      "invariant": false,
      "invariant_justification": "This is a data quality policy to prevent accidental duplicates. A business decision could allow same-address recipients (e.g., two different people at the same office). Policy, not structural integrity.",
      "testable_assertion": "Given a Shipment with an existing Recipient at Address X, when a new Recipient with Address X is added, then the operation MUST be rejected with a duplicate address error."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A new Shipment is being created",
      "when": "the creator specifies one Recipient",
      "then": "the Shipment is created with that Recipient as Primary, and all behavior is identical to the legacy single-recipient model"
    },
    {
      "id": "AC-2",
      "given": "A new Shipment is being created",
      "when": "the creator specifies multiple Recipients with delivery preferences for each",
      "then": "the Shipment is created with all Recipients, one designated Primary, each with independent delivery preferences and independent delivery status"
    },
    {
      "id": "AC-3",
      "given": "An existing single-recipient Shipment in production (pre-migration)",
      "when": "the migration runs",
      "then": "the Recipient is preserved with all original data, is marked as Primary, and no external-facing behavior changes"
    },
    {
      "id": "AC-4",
      "given": "An external partner API requests shipment data for a multi-recipient Shipment",
      "when": "the API responds using the legacy single-recipient format",
      "then": "the Primary Recipient's data is returned as the shipment's recipient, preserving backward compatibility"
    },
    {
      "id": "AC-5",
      "given": "An external partner API supports the new multi-recipient format",
      "when": "the API responds",
      "then": "all Recipients and their delivery preferences are included in the response"
    },
    {
      "id": "AC-6",
      "given": "A multi-recipient Shipment where Recipient A has been delivered but Recipient B has not",
      "when": "the shipment status is queried",
      "then": "the Shipment status is 'Partially Delivered' (or equivalent non-complete state), with per-recipient status available"
    },
    {
      "id": "AC-7",
      "given": "A multi-recipient Shipment",
      "when": "the last remaining Recipient is being removed",
      "then": "the operation is rejected; the Shipment must retain at least one Recipient"
    },
    {
      "id": "AC-8",
      "given": "A multi-recipient Shipment",
      "when": "the Primary Recipient is removed",
      "then": "the system either rejects the removal until a new Primary is designated, or automatically promotes the next Recipient to Primary"
    }
  ],

  "edge_cases": [
    {
      "scenario": "A Shipment with one Recipient has a second Recipient added, then the original (Primary) is removed",
      "expected_behavior": "The newly added Recipient is promoted to Primary. The Shipment remains valid with one Recipient."
    },
    {
      "scenario": "External partner API sends an update to a multi-recipient Shipment using the legacy single-recipient payload format",
      "expected_behavior": "The update applies to the Primary Recipient only. Other Recipients are unaffected. An event or warning should indicate partial update if applicable."
    },
    {
      "scenario": "Two Recipients on the same Shipment have conflicting delivery preferences (e.g., one requires morning delivery, another requires evening, but routing constrains them to a single trip)",
      "expected_behavior": "The system must surface the conflict. Business must decide: split into separate trips, negotiate preferences, or escalate. The system MUST NOT silently ignore one preference."
    },
    {
      "scenario": "A Shipment is in-transit and a new Recipient is added",
      "expected_behavior": "Business must define whether mid-transit modification is allowed. If allowed, routing must be recalculated. If not, the addition is rejected with an appropriate status-based error."
    },
    {
      "scenario": "Migration encounters a legacy Shipment with corrupted or null Recipient data",
      "expected_behavior": "The migration must quarantine the record, log it for manual review, and NOT create a Shipment with an invalid Recipient. Zero silent data loss."
    },
    {
      "scenario": "All Recipients on a multi-recipient Shipment have delivery failures",
      "expected_behavior": "Each Recipient gets an independent failure record. The Shipment status reflects total failure. Retry/return-to-sender logic must account for multiple addresses."
    },
    {
      "scenario": "A Shipment has 50+ Recipients",
      "expected_behavior": "System must define an upper bound. Unbounded recipient lists create routing complexity, UI problems, and potential abuse. A maximum should be enforced as a business policy (not invariant)."
    }
  ],

  "business_impact": {
    "financial": "Multi-recipient shipments could increase revenue per shipment by consolidating what were previously separate shipments into one. However, pricing models must evolve — a single-recipient flat rate no longer applies. There is risk of revenue leakage if a multi-recipient shipment is priced as a single delivery. Migration costs are non-trivial: schema migration on 2M records, API versioning, partner onboarding to new formats.",
    "operational": "Routing complexity increases significantly. Couriers now need optimized multi-stop routes per shipment. Dispatch, tracking, and proof-of-delivery systems must all support per-recipient granularity. Partial delivery states ('2 of 3 delivered') create new operational workflows for customer service, exception handling, and SLA tracking. Warehouse operations may need to pick/pack per recipient.",
    "user": "End users gain flexibility — e.g., sending gifts to multiple people in one order. But the UX must handle added complexity gracefully. Tracking pages must show per-recipient status. Notification systems must alert per-recipient, not just per-shipment. Sender experience becomes more complex; poor UX here will increase support tickets.",
    "risk": "HIGH risk in the migration and backward compatibility layer. 2M production records must migrate without behavioral regression. External partner APIs are the highest risk — partners may not update their integrations promptly, requiring indefinite backward compatibility. There is also risk of domain model confusion if 'Primary Recipient' semantics are not clearly defined and enforced. Partial delivery states introduce new failure modes in billing, SLA enforcement, and dispute resolution.",
    "stakeholders_affected": [
      { "group": "Senders / Shippers", "impact": "Gain ability to ship to multiple recipients in one transaction. Must learn new UI. Pricing may change." },
      { "group": "Recipients", "impact": "No change in delivery experience per se, but tracking and notifications now scoped to their specific delivery within a shared shipment." },
      { "group": "Couriers / Drivers", "impact": "Must handle multi-stop deliveries per shipment. Route optimization changes. Proof of delivery required per recipient. Workload per shipment increases." },
      { "group": "Customer Service", "impact": "Must handle partial delivery inquiries, per-recipient disputes, and more complex shipment states. Training and tooling updates required." },
      { "group": "External Partners / API Consumers", "impact": "HIGHEST IMPACT. Must either migrate to new API format or receive backward-compatible responses via Primary Recipient. Risk of data loss if they ignore secondary recipients." },
      { "group": "Finance / Billing", "impact": "Pricing model must evolve. Invoice line items may need per-recipient granularity. Revenue recognition for partial deliveries needs definition." },
      { "group": "Product / Engineering", "impact": "Significant engineering effort across data model, APIs, routing, tracking, notifications, and reporting. Phased rollout recommended." }
    ]
  },

  "confidence": {
    "level": 52,
    "reasoning": "The spec is directionally clear but critically underspecified. The product team states 'one or more Recipients' with 'different delivery preferences' but does not define: what delivery preferences consist of, whether a Primary Recipient concept exists, how pricing works, what shipment lifecycle transitions are affected, whether in-transit modifications are allowed, how external partner APIs should be versioned, or what the migration strategy is. These are not minor details — they are load-bearing business decisions that affect every acceptance criterion. Additionally, 'delivery preferences' is undefined and could range from time windows to safe-place instructions to authority-to-leave, each with different domain implications.",
    "high_confidence_areas": [
      "At-least-one-recipient invariant is universal in logistics",
      "Per-recipient delivery status is required by physical reality",
      "Backward compatibility with 2M existing records is non-negotiable",
      "External partner API backward compatibility is critical"
    ],
    "low_confidence_areas": [
      "Primary Recipient concept — assumed but not stated in spec",
      "Delivery preferences schema — completely undefined",
      "Pricing model changes — not addressed",
      "In-transit modification rules — not addressed",
      "Upper bound on recipients per shipment — not addressed",
      "Partner API versioning strategy — not addressed",
      "Partial delivery status naming and state machine — not addressed"
    ],
    "assumptions": [
      "A Primary Recipient designation is needed for backward compatibility with external APIs and legacy behavior",
      "Delivery preferences are per-recipient, not shared or inherited",
      "Existing single-recipient shipments will be migrated in-place rather than dual-written",
      "The external partner API will support a backward-compatible mode indefinitely",
      "Shipment status must reflect composite state across all recipients"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec does not define what 'delivery preferences' consists of. This is the core new capability and it is entirely unspecified. The data model, validation rules, and UI all depend on this definition.",
      "affected_stakeholders": ["Product", "Engineering", "Recipients", "Couriers"],
      "options": [
        "Define a minimal preference set (time window, safe place, signature required) and iterate",
        "Gather preference types from existing courier operations and model comprehensively"
      ],
      "recommendation": "Define a minimal viable preference schema before implementation begins. Start with time window preference and authority-to-leave as they are the most operationally impactful."
    },
    {
      "type": "ambiguity",
      "description": "No guidance on how external partner APIs should handle multi-recipient data. Partners currently receive single-recipient payloads. Breaking this contract will cause integration failures.",
      "affected_stakeholders": ["External Partners / API Consumers", "Engineering"],
      "options": [
        "Version the API: v1 returns Primary Recipient only, v2 returns all Recipients",
        "Add Recipients array to existing payload with backward-compatible single-recipient fields preserved",
        "Require all partners to migrate to new format with a deprecation timeline"
      ],
      "recommendation": "Option B — extend existing payload with a Recipients array while preserving the top-level recipient fields (populated from Primary). This minimizes partner disruption while enabling adoption."
    },
    {
      "type": "missing_context",
      "description": "No pricing or billing model defined for multi-recipient shipments. A shipment to 5 recipients at 5 addresses is fundamentally different in cost from a single-recipient shipment. Without pricing rules, the feature cannot ship to production.",
      "affected_stakeholders": ["Finance / Billing", "Senders / Shippers", "Product"],
      "options": [
        "Price per recipient (base + per-stop fee)",
        "Price by total route distance",
        "Price as separate shipments bundled with a discount"
      ],
      "recommendation": "Escalate to Finance and Product to define pricing model before engineering begins. This decision affects data model design (whether recipients share a price or have individual pricing)."
    },
    {
      "type": "ambiguity",
      "description": "Shipment lifecycle state machine is not updated for multi-recipient reality. Current states (Created, In Transit, Delivered, Failed) do not account for partial delivery. New states or sub-states are needed.",
      "affected_stakeholders": ["Customer Service", "Product", "Engineering", "Senders / Shippers"],
      "options": [
        "Add 'Partially Delivered' shipment-level status",
        "Keep shipment status as 'In Transit' until all recipients delivered, with per-recipient sub-statuses",
        "Derive shipment status from recipient statuses (no new explicit state)"
      ],
      "recommendation": "Option C — derive shipment-level status from the aggregate of recipient statuses. This avoids state synchronization bugs and makes the recipient the source of truth for delivery progress."
    }
  ],

  "rejection_reasons": []
}

